### Next.js Edge Middleware for Edge Config Rewrites

Source: https://vercel.com/docs/llms-full

Implements middleware to rewrite requests at the edge using Vercel Edge Config. The middleware fetches rewrite rules (source-to-destination path mappings) from Edge Config and applies them to incoming requests. This approach eliminates the need to redeploy when rewrite rules change and allows quick rollback to legacy servers if issues occur.

```TypeScript
import { get } from '@vercel/edge-config';
import { NextRequest, NextResponse } from 'next/server';

export const config = {
  matcher: '/((?!api|_next/static|favicon.ico).*)',
};

export default async function middleware(request: NextRequest) {
  const url = request.nextUrl;
  const rewrites = await get('rewrites'); // Get rewrites stored in Edge Config

  for (const rewrite of rewrites) {
    if (rewrite.source === url.pathname) {
      url.pathname = rewrite.destination;
      return NextResponse.rewrite(url);
    }
  }

  return NextResponse.next();
}
```

