### Configure Function Regions - Other Frameworks

Source: https://vercel.com/docs/functions/runtimes/edge

Set regional execution for Edge runtime functions in non-Next.js frameworks by exporting a config object with regions array. Runtime must be set to 'edge'. Handler receives request and response objects and returns JSON with execution region information.

```typescript
export const config = {
  runtime: 'edge', // this must be set to `edge`
  // execute this function on iad1 or hnd1, based on the connecting client location
  regions: ['iad1', 'hnd1'],
};

export default function handler(request: Request, response: Response) {
  return response.status(200).json({
    text: `I am an Vercel Function! (executed on ${process.env.VERCEL_REGION})`,
  });
}
```

```javascript
export const config = {
  runtime: 'edge', // this must be set to `edge`
  // execute this function on iad1 or hnd1, based on the connecting client location
  regions: ['iad1', 'hnd1'],
};

export default function handler(request, response) {
  return response.status(200).json({
    text: `I am an Vercel Function! (executed on ${process.env.VERCEL_REGION})`,
  });
}
```

